var rawInput = $runner.getModuleResult("入力_生年月日");
var text = "";
if (rawInput && typeof rawInput === "object" && rawInput.text) {
    text = String(rawInput.text);
} else if (typeof rawInput === "string") {
    text = rawInput;
}
text = text == null ? "" : String(text).trim();
var n = text.replace(/[\s\u3001\u3002,\.\-_\/\u30FB:;\uff01!\uff1f?\u300c\u300d\u300e\u300f\uff08\uff09()\u3000]/g, "");
n = n.replace(/[\u30A1-\u30F6]/g, function(c) {
    return String.fromCharCode(c.charCodeAt(0) - 0x60);
});

function hasRepeatMarker(t) {
    return (
        /(もう(いち|一)(ど|度|かい|回))/.test(t) ||
        /(もういっかい|もういっど)/.test(t) ||
        /(も(いち|一)(ど|度|かい|回))/.test(t) ||
        /(さいど(おねがい|お願い|きかせ|いって)?)/.test(t) ||
        /(再度(おねがい|お願い|きかせ|いって)?)/.test(t) ||
        /(まえ(に)?もど(って|る|して))/.test(t) ||
        /(前(に)?戻(って|る|して))/.test(t) ||
        /(きこえ(ない|ません|なかった|づらい))/.test(t) ||
        /(聞こえ(ない|ません|なかった|づらい))/.test(t) ||
        /(ききと(れない|れません|れなかった|りにくい))/.test(t) ||
        /(聞き取(れない|れません|れなかった|りにくい))/.test(t) ||
        /(くりかえ(し|して|しください))/.test(t) ||
        /(繰り返(し|して|しください))/.test(t)
    );
}
function hasWaitMarker(t) {
    return (
        /(ちょっと(まって|待って|待ち))/.test(t) ||
        /((少々|しょうしょう)(おまち|お待ち))/.test(t) ||
        /^(まって|待って)(ください)?$/.test(t) ||
        /(いま(かくにん|確認)(して|中|しています))/.test(t) ||
        /(今(確認|かくにん)(して|中|しています))/.test(t) ||
        /(しらべて|調べて)(います|いる|おります)/.test(t) ||
        /^(えーと|えっと|あのー|あの|うーん)$/.test(t)
    );
}

// REPEAT は最弱判定: 発話がほぼ repeat/wait 句だけ（正規化後 15 文字以内）の
// 場合のみ発火。実内容を含む長い発話は誤マッチを避けて必ず通常処理へ通す。
if (n.length > 0 && n.length <= 15 && (hasRepeatMarker(n) || hasWaitMarker(n))) {
    $runner.setResult("REPEAT");
} else {
    $runner.setResult("PASS");
}

