        rest = rest.replace(/^[、,。\s]+/, "");
        text = rest;
        changed = true;
        break;
      }
      // 読点・句点・空白の直後のフィラー（境界 1 文字を残して除去）
      var idx = -1;
      var search = 0;
      while (true) {
        var p = text.indexOf(f, search);
        if (p <= 0) { break; }
        var prev = text.charAt(p - 1);
        if (prev === "、" || prev === "," || prev === "。" ||
            prev === " " || prev === "\t" || prev === "\n") {
          idx = p;
          break;
