        search = p + 1;
      }
      if (idx > 0) {
        var tail = text.substring(idx + f.length).replace(/^[、,\s]+/, "");
        text = text.substring(0, idx) + tail;
        changed = true;
        break;
      }
    }
  }
  return text;
}

