        var prev = text.charAt(p - 1);
        if (prev === "、" || prev === "," || prev === "。" ||
            prev === " " || prev === "\t" || prev === "\n") {
          idx = p;
          break;
        }
        search = p + 1;
      }
      if (idx > 0) {
        var tail = text.substring(idx + f.length).replace(/^[、,\s]+/, "");
