      var m = re.exec(text);
      if (m) {
        text = text.substring(0, m.index);
        changed = true;
        break;
      }
    }
  }
  return text;
}

function normalizeText(raw) {
  if (raw === null || raw === undefined) { raw = ""; }
  raw = String(raw);
  var original = raw.replace(/^\s+|\s+$/g, "");

  var text = raw.replace(/，/g, "、").replace(/．/g, "。");
